#include <iostream>
using namespace std;

int main() {
    int num = 42;

    // Pointer declaration and initialization
    int* ptr = &num;

    // Reference declaration
    int& ref = num;

    cout << "Value of num: " << num << endl;
    cout << "Address of num (&num): " << &num << endl;
    cout << "Value through pointer (*ptr): " << *ptr << endl;
    cout << "Value through reference (ref): " << ref << endl;

    // Modify through reference
    ref = 100;
    cout << "After modifying ref, num = " << num << endl;

    // Modify through pointer
    *ptr = 200;
    cout << "After modifying *ptr, num = " << num << endl;

    return 0;
}

#include <iostream>
using namespace std;

// Pass by pointer
void doubleValue(int* ptr) {
    if (ptr != nullptr) {
        *ptr = *ptr * 2;
    }
}

// Pass by reference
void tripleValue(int& ref) {
    ref = ref * 3;
}

// Array traversal using pointer arithmetic
int sumArray(int* arr, int size) {
    int sum = 0;
    int* ptr = arr;
    for (int i = 0; i < size; i++) {
        sum += *(ptr + i);  // or sum += ptr[i]
    }
    return sum;
}

int main() {
    int x = 10;

    // Using pointer parameter
    doubleValue(&x);
    cout << "After doubleValue: " << x << endl;

    // Using reference parameter
    tripleValue(x);
    cout << "After tripleValue: " << x << endl;

    // Array with pointers
    int numbers[] = {5, 10, 15, 20, 25};
    int size = sizeof(numbers) / sizeof(numbers[0]);

    cout << "Sum of array: " << sumArray(numbers, size) << endl;

    // Pointer to array
    int* ptr = numbers;
    cout << "First element: " << *ptr << endl;
    cout << "Second element: " << *(ptr + 1) << endl;

    return 0;
}

#include <iostream>
#include <memory>
using namespace std;

class Student {
public:
    string name;
    int rollNo;

    Student(string n, int r) : name(n), rollNo(r) {
        cout << "Constructor: " << name << endl;
    }

    ~Student() {
        cout << "Destructor: " << name << endl;
    }

    void display() {
        cout << "Name: " << name << ", Roll No: " << rollNo << endl;
    }
};

int main() {
    // Dynamic memory allocation using new
    int* dynamicNum = new int(50);
    cout << "Dynamic integer: " << *dynamicNum << endl;
    delete dynamicNum;

    // Dynamic array
    int* arr = new int[5]{10, 20, 30, 40, 50};
    for (int i = 0; i < 5; i++) {
        cout << "arr[" << i << "] = " << arr[i] << endl;
    }
    delete[] arr;

    // Pointer to pointer
    int** ptr2ptr;
    int* ptr1;
    int value = 100;
    ptr1 = &value;
    ptr2ptr = &ptr1;
    cout << "Value via pointer to pointer: " << **ptr2ptr << endl;

    // Smart Pointers (C++11)
    cout << "\n--- Smart Pointers ---" << endl;

    // unique_ptr - exclusive ownership
    unique_ptr<Student> student1 = make_unique<Student>("Alice", 101);
    student1->display();

    // shared_ptr - shared ownership with reference counting
    shared_ptr<Student> student2 = make_shared<Student>("Bob", 102);
    shared_ptr<Student> student3 = student2;
    cout << "Use count: " << student2.use_count() << endl;

    // weak_ptr - non-owning reference to shared_ptr
    weak_ptr<Student> weakStudent = student2;
    if (auto locked = weakStudent.lock()) {
        cout << "Weak pointer accessed: ";
        locked->display();
    }

    cout << "\nEnd of main - smart pointers auto-delete" << endl;
    return 0;
}
